import math
from pathlib import Path

import pytest
import yaml

import graph
from astar import a_star


FIXTURE_DIR = Path(__file__).parent / 'fixtures'
FIXTURE_FILES = sorted(FIXTURE_DIR.glob('*.yaml'))


def _load_fixture(path):
    with open(path) as f:
        return yaml.safe_load(f)


def _build_graph(fixture):
    edges = [tuple(e) for e in fixture['edges']]
    return graph.create_graph(edges, is_directed=fixture.get('directed', False))


def _make_heuristic(h_map):
    def heuristic(vertex):
        return h_map[vertex.element()]
    return heuristic


@pytest.fixture(params=FIXTURE_FILES, ids=lambda p: p.stem)
def case(request):
    return _load_fixture(request.param)


def test_astar_matches_fixture(case):
    G, w = _build_graph(case)
    start = G.get_vertex(case['start'])
    goal = G.get_vertex(case['goal'])
    heuristic = _make_heuristic(case['heuristic'])

    path, length = a_star((G, w), start, goal, heuristic)

    if case.get('expected_path', '__unset__') is None:
        # unreachable goal
        assert path is None
        assert length == math.inf
        return

    actual = [v.element() for v in path] if path is not None else None

    if 'expected_path' in case:
        assert actual == case['expected_path']
    elif 'acceptable_paths' in case:
        # symmetric graphs may have more than one optimal path; any is fine
        assert actual in case['acceptable_paths']
    else:
        pytest.fail(f"fixture {case['name']} declares neither expected_path nor acceptable_paths")

    assert length == case['expected_length']


def test_astar_start_equals_goal():
    # degenerate case: zero-length path of a single vertex
    G, w = graph.create_graph([('a', 'b', 1)], is_directed=True)
    a = G.get_vertex('a')
    path, length = a_star((G, w), a, a, lambda v: 0)
    assert path == [a]
    assert length == 0
